  await checkout(1, 3);

  try {
    await checkout(1, 100);
  } catch (error) {
    if (error instanceof Error && error.message === 'Insufficient stock') {
      insufficientStockCaught = true;
    } else {
      throw error;
    }
  }

  const product = await prisma.product.findUnique({ where: { id: 1 } });
